        let parts: Vec<&str> = line.split('\t').collect();
        if parts.is_empty() { continue; }
        let word = parts[0].to_lowercase();
        if word.chars().any(|c| c.is_ascii_digit()) { continue; }
        if word.len() < 2 { continue; }
